        if(flag==-1) tg=ksm(tg,mod-2,mod);
        for(int j=0;j&lt;len;j+=i){
            int buf=1;
            for(int k=j;k&lt;j+l;k++){
                int tt=1ll*buf*f[k+l]%mod;
                f[k+l]=((f[k]-tt)%mod+mod)%mod;
                f[k]=(f[k]+tt)%mod;buf=1ll*buf*tg%mod;
            }
        }
    }
    if(flag==1) return;
    int inv=ksm(len,mod-2,mod);for(int i=0;i&lt;len;i++) f[i]=1ll*f[i]*inv%mod;
}
