struct Matrix{
    int n,m,a[N][N];
    inline void Clear(){mset(a,0);n=m=0;}
    inline Matrix operator * (const Matrix &amp;b)const{
        assert(m==b.n);
        Matrix c;c.Clear();c.n=n;c.m=b.m;
        rep(i,1,c.n)rep(j,1,c.m)rep(k,1,m){
            c.a[i][j]=(c.a[i][j]+a[i][k]*b.a[k][j]%mod)%mod;
        }
        return c;
    }
