inline int dinic(int k,int flow){
    if(k==t) return flow;int rest=flow,x;vis[k]=1;
    for(x=now[k];x&amp;&amp;rest;x=li[x].next){
        int to=li[x].to,f=li[x].f,w=li[x].w;
