inline void dij(){
    Q.push(mp(0,1));fill(d+1,d+n+1,INF);mset(vis,0);d[1]=0;
    while(Q.size()){
        P top=Q.top();Q.pop();vis[top.se]=1;
        Next(top.se){
            int to=li[x].to,w=li[x].w;
            if(vis[to]||d[to]&lt;=d[top.se]+w) continue;
            d[to]=d[top.se]+w;Q.push(mp(-d[to],to));
        }
    }
