T3
首先考虑后缀自动机，因为后缀自动机存储了所有子串的信息，那么对于一个状态，里面除了最长的那个字符串，其余字符串一定是不重要的，而如果一个状态有至少两个转移，那么这个状态里最长的那个串一定是重要的，因为在这个串前面加字符得到的字符串在别的状态里， 集合不一样，而往后加一个字符有不同加法，所以一定也不一样。
如果一个状态没有转移，即  这个状态，里面最长的串一定也是重要的，而对于只有一个转移的状态，如果它是后缀，那么也是重要的，因为它往后加字符之后得到的串的  一定不和原来一样。如果一个状态里面最长的字符串是重要的，那么我们称这个状态也是重要的，我们需要统计所有重要的状态，和在  树上，从根到  这个路径上所有不重要的状态的个数之和。前一个好统计，后一个不好统计。因为树的形态会变化，所以一种思路是我们用 LCT 去维护 fail 树，操作就是在一个边上加上一个点，以及给一个点加一个叶子。
不过 LCT 常数太大了，只能做 ，切队长直接魔改了 LCT 过掉了这个题，我们考虑倒过来做，从后向前做，这样我们就可以近似认为树的状态没有变化，而我们需要维护每个点是否重要，以及一个点到根不重要点的数量，操作相当于树上单点改，链求和，树状数组树上差分做就可以。注意操作数是  的，因为改变次数和转移数和节点数是同一级别的。
代码：
int n,ans[N];
char s[N];
vi e[N];int L[N],R[N],itot;

struct BIT{
    int p[N];
    inline int lowbit(int x){return x&amp;(-x);}
    inline void Add(int w,int x){
        // printf("Add w=%d x=%d\n",w,x);
        for(int i=w;i&lt;=itot;i+=lowbit(i)) p[i]+=x;
    }
    inline int Ask(int w){
        // printf("Ask w=%d\n",w);
        int res=0;for(int i=w;i;i-=lowbit(i)) res+=p[i];return res;
    }
}bit;
struct Ques{
    int op,k,x;
    inline Ques(){}
    inline Ques(int op,int k,int x) : op(op),k(k),x(x) {}
};
vc&lt;Ques&gt; qu[N];
struct SAM{
    int Link[N&lt;&lt;1],tot,Len[N&lt;&lt;1],ch[N&lt;&lt;1][10],cnt[N&lt;&lt;1],last,Ans;
    inline SAM(){tot=1;Link[1]=-1;Len[1]=0;last=1;Ans=0;}
    inline void Insert(int c,int id){
        // printf("first Ans=%d\n",Ans);
        vc&lt;P&gt; v;v.clear();
        int now=++tot;Len[now]=Len[last]+1;int p=last;
        while(p!=-1&amp;&amp;!ch[p][c]){
            ch[p][c]=now;cnt[p]++;
            if(cnt[p]==1&amp;&amp;p!=1) Ans--,v.pb(mp(p,-1));
            else if(cnt[p]==2&amp;&amp;p!=1) Ans++,v.pb(mp(p,1));
            p=Link[p];
        }
        // printf("Ans=%d\n",Ans);
        if(p==-1){Link[now]=1;}
        else{
            int q=ch[p][c];if(Len[q]==Len[p]+1){Link[now]=q;}
            else{
                int clone=++tot;Link[clone]=Link[q];rep(i,0,9) ch[clone][i]=ch[q][i];cnt[clone]=cnt[q];
                if(cnt[clone]&gt;=2) Ans++;else if(cnt[clone]==1) v.pb(mp(clone,-1));Len[clone]=Len[p]+1;
                Link[q]=clone;Link[now]=clone;while(p!=-1&amp;&amp;ch[p][c]==q) ch[p][c]=clone,p=Link[p];
            }
        }
        last=now;Ans++;v.pb(mp(now,-1));qu[id].pb(Ques(1,now,-1));
        dec(i,0,(int)v.size()-1) qu[id].pb(Ques(2,v[i].fi,v[i].se));
    }
    inline void dfs(int k,int fa){
        L[k]=++itot;if(cnt[k]==1) qu[n+1].pb(Ques(2,k,1));
        for(int to:e[k])if(to!=fa){dfs(to,k);}
        R[k]=itot;
    }
    inline void Build(){
        rep(i,1,tot) if(Link[i]!=-1){
            e[Link[i]].pb(i);
            // printf("Add %d %d\n",Link[i],i);
        }dfs(1,0);
    }
}sam;

inline void Solve(){
    // rep(i,1,n) printf("%d ",ans[i]);puts("");
    dec(i,1,n+1){
        for(Ques now:qu[i]) if(now.op==1) ans[i]+=bit.Ask(L[now.k]);
        else{
            if(now.k==1) continue;
            // printf("Ope Add %d %d\n",now.k,now.x);
            bit.Add(L[now.k],now.x);bit.Add(R[now.k]+1,now.x*(-1));
        }
    }
}

int main(){
    // freopen("my.in","r",stdin);
    // freopen("my.out","w",stdout);
    read(n);scanf("%s",s+1);
    rep(i,1,n) sam.Insert(s[i]-'0',i),ans[i]=sam.Ans;sam.Build();
    Solve();rep(i,1,n) printf("%d ",ans[i]);
    return 0;
}

李超树是一个可以多个分段一次函数，并取某个端点上所有一次分段函数的最值。基本李超树需要维护两个操作：

在  加入一条线段。
询问在  处的最值。

李超树中，每个节点我们存储的函数编号为在这个节点代表区间中点取得最值的函数编号。
插入时，我们首先向线段树一样找到  这个区间，如果这个区间以前的最优线段在中点处没有我们新加入的函数优，我们就交换两个线段编号，把原先在这个区间的线段继续向下递归插入。
继续向下递归插入是这个函数有可能在左右半个区间中的一个中更优，我们可以通过分类讨论来往下递归。
我们查询最值时，只要查询这个路径上所有的线段在这个点取得的值，取  即可。
关于复杂度，查询显然是  的，而对于插入， 一共被拆成  个区间，向下查又是一个 ，所以复杂度应该是 。
