inline int Lca(int a,int b){
    if(dep[a]&lt;dep[b]) swap(a,b);
    dec(i,0,20) if(dep[fa[a][i]]&gt;=dep[b]) a=fa[a][i];if(a==b) return a;
    dec(i,0,20) if(fa[a][i]!=fa[b][i]) a=fa[a][i],b=fa[b][i];return fa[a][0];
}
