    rep(i,0,n-1) b[i].y=B[bit1(i)][bit2(i)];w1.x=1;w2=(cp){mod-1,mod-1};
    FWT(b,n);FWT(f,n);
    rep(i,0,n-1) b[i]=ksm(b[i],t);
    rep(i,0,n-1) f[i]=f[i]*b[i];
